import React from "react"
import TypesenseInstantSearchAdapter from "typesense-instantsearch-adapter"
import { InstantSearch, connectRange, connectRefinementList, connectCurrentRefinements, connectStats, connectSearchBox, connectHits, connectPagination } from "react-instantsearch-dom"
import Hits from "../Hits"
import { withLocation, typesenseSearchConfig } from "../../util"

import queryString from 'query-string'

import Slider from '@material-ui/core/Slider';
import Chip from '@material-ui/core/Chip';
import TextField from '@material-ui/core/TextField';
import Checkbox from '@material-ui/core/Checkbox';
import FormGroup from '@material-ui/core/FormGroup';
import FormControlLabel from '@material-ui/core/FormControlLabel';
import Pagination from '@material-ui/lab/Pagination'
import Autocomplete from '@material-ui/lab/Autocomplete';
import { withStyles } from '@material-ui/core/styles';

import classNames from "classnames/bind"
import styles from "./styles.module.scss"

const ValueSlider = withStyles({
	valueLabel: {
		top: 22,
		'& *': {
			background: 'transparent',
			color: styles.textColor,
		},
	}
})(Slider)

function parseYears(str) {
	const match1 = str.match(/^(\d{4})(-)?(\d{4})?$/)
	if (match1) {
		// console.log('matches regex1', match1)
		return {
			min: parseInt(match1[1]),
			max: match1[2] === "-" ? (match1[3] === undefined ? undefined : parseInt(match1[3])) : parseInt(match1[1])
		}
	}
	else {
		const match2 = str.match(/^-(\d{4})$/)
		if (match2) {
			// console.log('matches regex2')
			return {
				max: parseInt(match2[1])
			}
		}
	}
	return {}
}

function stringifyYears({min, max}) {
	if (min === max)
		return `${min}`
	return `${min || ""}-${max || ""}`
}

function SearchArea({ params, parseOptions, lang }) {

	const cx = classNames.bind(styles);

	const typesenseInstantsearchAdapter = new TypesenseInstantSearchAdapter(typesenseSearchConfig)
	const searchClient = typesenseInstantsearchAdapter.searchClient

	let refineCollection = null
	let refineAuthors = null
	let refineTopics = null
	let refineTags = null

	if (params.collection) {
		refineCollection = Array.isArray(params.collection) ? params.collection : [params.collection]
	}
	if (params.authors) {
		refineAuthors = Array.isArray(params.authors) ? params.authors : [params.authors]
	}
	if (params.topics) {
		refineTopics = Array.isArray(params.topics) ? params.topics : [params.topics]
	}
	if (params.tags) {
		refineTags = Array.isArray(params.tags) ? params.tags : [params.tags]
	}

	function updateURL() {
		window.history.replaceState(null, "", `?${queryString.stringify(params, parseOptions)}`)
	}

	const Stats = ({ processingTimeMS, nbHits }) => (
		<div className={cx("stats")}>{nbHits} results found in {processingTimeMS} ms</div>
	)

	function SectionTitle({ title, onClick }) {
		return(
			<div className={cx("sectionTitle")}>
				{title}
				{onClick && <span className={cx("clear")} onClick={onClick} onKeyDown={onClick} role="button" tabIndex={0}>Clear</span>}
			</div>
		)
	}

	const SearchBox = ({ currentRefinement, isSearchStalled, refine }) => {
		return(
			<FormGroup noValidate action="" role="search">
				<TextField
					type="search"
					value={currentRefinement}
					onChange={event => {
						params.q = event.target.value
						updateURL()
						refine(event.target.value)
					}}
					variant="outlined"
					label="Search"
					size="small"
					fullWidth
				/>
				{/*isSearchStalled ? 'My search is stalled' : ''*/}
			</FormGroup>
		)
	}

	const SuggestList = ({ title, items, attribute, currentRefinement, refine }) => {

		if (!items.length) return null

		return(
			<div className={cx("section")}>
				<SectionTitle title={title} />
				<Autocomplete
					multiple
					options={items}
					getOptionLabel={item => item.label}
					getOptionSelected={(option, value) => option.label === value.label}
					onChange={(event, value, reason) => {
						params[attribute] = value.map(v => v.label)
						updateURL()
						refine(value.map(v => v.label))
					}}
					disableClearable
					autoHighlight
					clearOnEscape
					filterSelectedOptions
					// disableOpenOnClick // for https://github.com/mui-org/material-ui/issues/23164
					value={items.filter(item => currentRefinement.includes(item.label))}
					ChipProps={{size: "small"}}
					renderInput={(params) => (
						<TextField
							{...params}
							variant="outlined"
							size="small"
							placeholder={`Search ${attribute}`}
						/>
					)}
				/>
			</div>
		)
	}

	const RefinementList = ({ title, searchable=false, showMore, items, currentRefinement, attribute, isFromSearch, refine, searchForItems }) => {

		const searchBox = React.useRef(null)

		if (!items.length) return null

		return(
			<div className={cx("section")}>
				<FormGroup>
					<SectionTitle title={title} />
					{searchable &&
						<TextField
							type="search"
							onChange={event => searchForItems(event.currentTarget.value)}
							label="Search"
							size="small"
							inputRef={searchBox}
						/>
					}
					{items.map((item, i) => (
						<div className={cx("filterItem")} key={`filteritem${i}`}>
							<FormControlLabel
								control={
									<Checkbox
										checked={item.isRefined}
										onChange={e => {
											if (searchable) {
												searchBox.current.value = ""
											}
											params[attribute] = item.value
											updateURL()
											refine(item.value)
										}}
										name={item.label}
										size="small"
									/>
								}
								label={
									<div className={cx("checkboxLabel")}>
										{item.label}
										<span className="blob-small-span left-margin">{item.count}</span>
									</div>
								}
								key={item.label}
							/>
						</div>
					))}

				</FormGroup>
			</div>
		)
	};

	function updateParams(items) {
		params = {q: params.q}
		items.map(item => {
			if (item.attribute !== "year") {
				params[item.attribute] = item.currentRefinement
			}
			else {
				params.years = stringifyYears(item.currentRefinement)
			}
			return
		})
	}

	const CurrentRefinements = ({ items, refine, createURL }) => {
		React.useEffect(() => {
			updateParams(items)
			updateURL()
		}, [items])
		if (items.length === 0)
			return null
		return(
			<div className={cx("section")}>
				<SectionTitle title="Current Refinements" onClick={() => refine(items)} />
				<div className={cx("chipArray")}>
					{items.map((item, i) => {
						return(
							item.items
								? item.items.map((r, j) => {
										return(
											<Chip
												label={(["topics", "tags"].includes(item.attribute) ? item.attribute + ": " : "") + r.label}
												size="small"
												onDelete={() => {
													refine(r.value)
												}}
												key={`chip${i}-${j}`}
											/>
										)
									})
								: <Chip
										label={item.label}
										size="small"
										onDelete={() => {
											refine(item.value)
										}}
									/>
						)
					})}
				</div>
			</div>
		)

	}

	const RangeSlider = ({ min, max, currentRefinement, canRefine, refine }) => {
		
		const [stateMin, setStateMin] = React.useState(min);
	  const [stateMax, setStateMax] = React.useState(max);

	  React.useEffect(() => {
	    if (canRefine) {
	      setStateMin(currentRefinement.min);
	      setStateMax(currentRefinement.max);
	    }
	  }, [currentRefinement.min, currentRefinement.max]);

	  if (min === max) {
	    return null;
	  }

	  function handleChange(event, newValue) {
	  	const min = newValue[0]
	  	const max = newValue[1]
	    if (currentRefinement.min !== min || currentRefinement.max !== max) {
				params.years = stringifyYears({min: min, max: max})
				updateURL()
	      refine({ min, max });
	      setStateMin(min);
		    setStateMax(max);
	    }
	  }

	  return (
			<div className={cx("section")}>
				<FormGroup>
					<SectionTitle title="Year" />
			    <ValueSlider
		        value={[currentRefinement.min, currentRefinement.max]}
		        min={min}
		        max={max}
		        onChange={handleChange}
		        valueLabelDisplay="on"
		        // aria-labelledby="range-slider-demo"
		      />
				</FormGroup>
			</div>
	  );
	};

	const AISPagination = ({ currentRefinement, nbPages, refine, ...rest }) => {
		if (nbPages < 2) return null
		if (currentRefinement > nbPages) {
			params.p = nbPages
			updateURL()
			refine(nbPages)
		}
		return(
			<Pagination
				count={nbPages}
				page={currentRefinement}
				onChange={(event, page) => {
					params.p = page
					updateURL()
					refine(page)
				}}
			/>
		)
	}

	const CustomStats = connectStats(Stats)
	const CustomSearchBox = connectSearchBox(SearchBox)
	const CustomHits = connectHits(Hits)
	const CustomSuggestList = connectRefinementList(SuggestList)
	const CustomRefinementList = connectRefinementList(RefinementList)
	const CustomRangeSlider = connectRange(RangeSlider)
	const CustomPagination = connectPagination(AISPagination)
	const CustomCurrentRefinements = connectCurrentRefinements(CurrentRefinements);

	const collectionsLabel = {
		pages: "Pages",
		members: "Members",
		abridged: "aBRIDGEd",
		thaipublica: 'เศรษฐศาสตร์เข้า "ท่า"',
		pierspectives: "PIERspectives",
		dp: "Discussion Paper",
		conferences: "Conferences",
		workshops: "Workshops",
		seminars: "Seminars",
		announcements: "Announcements",
		blog: "Blog Posts"
	}

	return (
		<InstantSearch searchClient={searchClient} indexName={`all_${lang}`}>
			<div className={cx("grid")}>
				<div className={cx("left")}>
					<CustomCurrentRefinements />
					<CustomRefinementList
						title="Collections"
						attribute="collection"
						defaultRefinement={refineCollection}
						transformItems={items => items.map(item => ({...item, label: collectionsLabel[item.label]}))}
					/>
					<CustomSuggestList
						title="Authors"
						attribute="authors"
						// operator="and"
						defaultRefinement={refineAuthors}
					/>
					<CustomSuggestList
						title="Topics"
						attribute="topics"
						// operator="and"
						defaultRefinement={refineTopics}
					/>
					<CustomSuggestList
						title="Tags"
						attribute="tags"
						// operator="and"
						defaultRefinement={refineTags}
					/>
					<CustomRangeSlider 
						attribute="year"
						defaultRefinement={params.years && parseYears(params.years)}
					/>
				</div>
				<div className={cx("right")}>
					<div className={cx("searchGroup")}>
						<CustomSearchBox defaultRefinement={params.q} />
						<CustomStats />
					</div>
					<CustomHits lang={lang}/>
					<div className={cx("pagination")}>
						<CustomPagination defaultRefinement={params.p} />
					</div>
				</div>
			</div>
		</InstantSearch>
	)
}
		
export default withLocation(SearchArea)